section.programlisting:
1 #ifndef HDEF_EVENTBUS
2 #define HDEF_EVENTBUS
3 
4 #include <vector>
5 #include <algorithm>
6 #include <functional>
7 #include <utility>
8 #include <unordered_map>
9 #include <typeindex>
10 
11 namespace Mochi::Event
12 {
13     using SubscriptionHandler = size_t;
14     using SubscriberFunc = std::function<void(const void *)>;
15     using SubscriberPair = std::pair<SubscriptionHandler, SubscriberFunc>;
16     class EventBus
17     {
18     private:
19         SubscriptionHandler mLastSubscriptionHandler;
20         std::vector<SubscriptionHandler> mFreeSubscriptionHandlers;
21         std::unordered_map<std::type_index, std::vector<SubscriberPair>> mSubscribersMap;
22 
23         SubscriptionHandler GetNextSubscriptionHandler()
24         {
25             if (mFreeSubscriptionHandlers.size() == 0)
26             {
27                 return mLastSubscriptionHandler++;
28             }
29             else
30             {
31                 SubscriptionHandler free = mFreeSubscriptionHandlers.back();
32                 mFreeSubscriptionHandlers.pop_back();
33                 return free;
34             }
35         }
36 
37     public:
38         EventBus() : mLastSubscriptionHandler(1) {}
39         ~EventBus()
40         {
41             mFreeSubscriptionHandlers.clear();
42             mSubscribersMap.clear();
43         }
44 
45         template <typename EventType>
46         SubscriptionHandler Subscribe(std::function<void(const EventType &)> callback)
47         {
48             auto &subscribers = mSubscribersMap[typeid(EventType)];
49             auto handler = GetNextSubscriptionHandler();
50             subscribers.emplace_back(handler, [callback](const void *e)
51                                      { callback(*static_cast<const EventType *>(e)); });
52             return handler;
53         }
54         template <typename EventType>
55         void Unsubscribe(SubscriptionHandler handler)
56         {
57             auto it = mSubscribersMap.find(typeid(EventType));
58             if (it == mSubscribersMap.end())
59                 return; // There was not an event of that type
60 
61             auto &subscribers = it->second;
62             auto was = subscribers.size();
63             subscribers.erase(
64                 std::remove_if(subscribers.begin(), subscribers.end(),
65                                [handler](auto &pair)
66                                { return pair.first == handler; }),
67                 subscribers.end());
68             if (was != subscribers.size())
69                 mFreeSubscriptionHandlers.push_back(handler);
70         }
71         template <typename EventType>
72         void Publish(const EventType &event)
73         {
74             auto it = mSubscribersMap.find(typeid(EventType));
75             if (it != mSubscribersMap.end())
76             {
77                 for (auto &[id, subscriber] : it->second)
78                 {
79                     subscriber(&event);
80                 }
81             }
82         }
83     };
84 }
85 
86 #endif
